# ─────────────────────────────────────────────────────────────────────────────
# PROMPT GENERATION
# ─────────────────────────────────────────────────────────────────────────────
def build_prompt(subject, aspect, style_suffix):
    return (f"A highly detailed professional photograph of {subject}, "
            f"{aspect.replace(':', ' to ')} aspect ratio, {style_suffix}, "
            f"8K resolution, professional color grading with rich tonal range, "
            f"emotionally compelling composition")

def main():
    all_prompts = []

    # Days 1-4
    for theme in THEMES_DAYS_1_4:
        for i, subject in enumerate(theme["subjects"]):
            all_prompts.append({
                "day": theme["day"],
                "theme": theme["name"],
                "index": i + 1,
                "prompt": build_prompt(subject, theme["aspect"], ""),
                "aspect": theme["aspect"],
                "filename": f"day{theme['day']:02d}_{theme['name']}_{i+1:02d}.png"
            })

    # Days 6-29
    for theme in DAY_THEMES_6_29:
        day = theme["day"]
        name = theme["name"]
        aspect = theme["aspect"]
        subjects = theme["subjects"]
        for i, subject in enumerate(subjects):
            style = PHOTOGRAPHY_STYLES[i % len(PHOTOGRAPHY_STYLES)]
            all_prompts.append({
                "day": day,
                "theme": name,
                "index": i + 1,
                "prompt": build_prompt(subject, aspect, style),
                "aspect": aspect,
                "filename": f"day{day:02d}_{name}_{i+1:02d}.png"
            })

    # Validate
    for d in range(1, 30):
        if d == 5:
            continue  # Day 5 done separately
        count = len([p for p in all_prompts if p["day"] == d])
        if count != 50:
            print(f"WARNING: Day {d} has {count} prompts (expected 50)")
        else:
            print(f"Day {d:02d}: {count} prompts ✓")

    with open(OUTPUT_PATH, 'w', encoding='utf-8') as f:
        json.dump(all_prompts, f, indent=2, ensure_ascii=False)
    print(f"\nTotal: {len(all_prompts)} prompts saved to {OUTPUT_PATH}")

if __name__ == "__main__":
    main()
